use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};

const BACKEND_API: &str = "api_backend";
const BACKEND_STATIC: &str = "static_backend";
const BACKEND_AUTH: &str = "auth_backend";

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    if !is_valid_request(&req) {
        return Ok(Response::from_status(StatusCode::BAD_REQUEST)
            .with_body_text_plain("Invalid request"));
    }

    let backend_name = match route_request(path, method) {
        Some(backend) => backend,
        None => {
            return Ok(Response::from_status(StatusCode::NOT_FOUND)
                .with_body_text_plain("Not found"));
        }
    };

    sanitize_headers(&mut req);

    add_security_headers(&mut req);

    let mut beresp = match req.send(backend_name) {
        Ok(resp) => resp,
        Err(e) => {
            log::error!("Backend error: {}", e);
            return Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain("Backend unavailable"));
        }
    };

    add_response_security_headers(&mut beresp);

    Ok(beresp)
}

fn route_request(path: &str, method: &Method) -> Option<&'static str> {
    if path.starts_with("/api/") {
        Some(BACKEND_API)
    } else if path.starts_with("/auth/") || path.starts_with("/login") {
        Some(BACKEND_AUTH)
    } else if path.starts_with("/static/") || path.starts_with("/assets/") {
        if method == Method::GET || method == Method::HEAD {
            Some(BACKEND_STATIC)
        } else {
            None
        }
    } else if path == "/" || path.starts_with("/index") {
        Some(BACKEND_STATIC)
    } else {
        None
    }
}

fn is_valid_request(req: &Request) -> bool {
    if let Some(host) = req.get_header_str(header::HOST) {
        if host.is_empty() || host.len() > 255 {
            return false;
        }
    } else {
        return false;
    }

    let path = req.get_path();
    if path.is_empty() || path.len() > 2048 {
        return false;
    }

    if path.contains("..") || path.contains("//") {
        return false;
    }

    if let Some(content_length) = req.get_header_str(header::CONTENT_LENGTH) {
        if let Ok(length) = content_length.parse::<u64>() {
            if length > 10_485_760 {
                return false;
            }
        } else {
            return false;
        }
    }

    true
}

fn sanitize_headers(req: &mut Request) {
    let headers_to_remove = [
        "X-Forwarded-Host",
        "X-Forwarded-Server",
        "X-Real-IP",
        "Proxy-Authorization",
    ];

    for header_name in &headers_to_remove {
        req.remove_header(header_name);
    }
}

fn add_security_headers(req: &mut Request) {
    if let Some(client_ip) = req.get_client_ip_addr() {
        req.set_header("X-Forwarded-For", client_ip.to_string());
    }

    req.set_header("X-Forwarded-Proto", "https");
}

fn add_response_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains",
    );
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Content-Security-Policy",
        "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self'; connect-src 'self'; frame-ancestors 'none';",
    );
    resp.set_header(
        "Permissions-Policy",
        "geolocation=(), microphone=(), camera=()",
    );

    resp.remove_header("Server");
    resp.remove_header("X-Powered-By");
}